import{_ as t,o as a,c as p,ai as s}from"./chunks/framework.CzqNhXfh.js";const u=JSON.parse('{"title":"23.10月纪录与总结","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"essays/articles/article-004.md","filePath":"essays/articles/article-004.md","lastUpdated":1776825361000}'),r={name:"essays/articles/article-004.md"};function o(c,e,l,i,_,n){return a(),p("div",null,[...e[0]||(e[0]=[s('<h1 id="_23-10月纪录与总结" tabindex="-1">23.10月纪录与总结 <a class="header-anchor" href="#_23-10月纪录与总结" aria-label="Permalink to &quot;23.10月纪录与总结&quot;">​</a></h1><blockquote><p>子昱 闲谈之余 2023年11月5日 09:58 湖北</p></blockquote><p>10月发生的事情太多，我的脑海中混乱不已。</p><p>管科年会——南京比赛——与她在一起</p><p>每件事情都离不开她的身影。这是一段纠结万分，顾虑万千的关系。</p><p>到最后，三种选项中，我们冲动地选择了在一起。</p><p>我尝到了恋爱的甜蜜，那种感觉让人不知疲倦。眼里全是她。</p><p>但冷静下来的我和她也发现了许许多多的问题，这是那个夜晚我们抛之脑后的东西。我们都沉默了。</p><p>我心里有预期，但突如其来的打击免不了失落。</p><p>她很特殊，思想与常人不同，经历同样如此。有时，我不知如何去应对她。在一段关系当中，我可以变得无比包容。这或许不是因为她一人，可能对另一半我都可以做到。她说，&quot;你这是溺爱&quot;。</p><p>可能是的。由于喜欢，我愿意去努力维系一段关系。一段注定不能圆满的关系。她的特性让人感到理解而疑惑。最后，她也许迫于现实，结一段缘；也许是孤独终老。我孤身前往下一篇章。</p><p>很奇怪的她，很奇怪的一段关系。表面的谈笑掩盖不住内心的落寞。遇见她是我的宿命，一段跌宕起伏的经历也是人生的意义。</p><p>山一程，水一程。时间还有很久，不必着急。</p><p>叩问此刻的我，你期望这两年如何过？我回答不上来。可能仅仅想维持这段关系，与她走完最后两年。</p><p>但心里有一些慰藉：我其实没有问题，仅仅是期望一段正常的恋爱。将更多的心思放在下一旅途的起点上，事业心会占据上风。</p>',15)])])}const m=t(r,[["render",o]]);export{u as __pageData,m as default};
